// ===== Player fighter, nose points RIGHT, on transparent bg =====
// padding ~10% for glow bloom
ctx.save();
ctx.lineJoin = 'round';
ctx.lineCap = 'round';

const cx = W * 0.5;
const cy = H * 0.5;

// Useful anchor coords (NOSE at right ~ x=88, TAIL/engines at left ~ x=10)
const noseX = W * 0.90;     // 86.4
const tailX = W * 0.115;    // ~11

// ---------- soft underbelly shadow (subtle, grounds the ship) ----------
ctx.save();
ctx.globalAlpha = 0.28;
ctx.fillStyle = 'rgba(0,0,0,0.55)';
ctx.beginPath();
ctx.ellipse(cx + 2, cy + H * 0.30, W * 0.40, H * 0.12, 0, 0, Math.PI * 2);
ctx.fill();
ctx.restore();

// =====================================================================
// SWEPT-BACK WINGS (drawn first, beneath fuselage)
// =====================================================================
// Upper wing
function drawWing(sign) {
  // sign = -1 for top wing, +1 for bottom wing
  const yEdge = cy + sign * H * 0.46;     // outer tip y
  const yRoot = cy + sign * H * 0.10;     // root near fuselage
  ctx.save();
  ctx.beginPath();
  ctx.moveTo(W * 0.60, cy + sign * H * 0.05);           // front root (near cockpit area)
  ctx.lineTo(W * 0.40, yEdge);                          // wing leading-mid to tip area
  ctx.lineTo(W * 0.165, yEdge * 0.5 + cy * 0.5 + sign * H * 0.32); // swept-back tip (toward tail)
  ctx.lineTo(W * 0.205, yRoot);                         // rear root
  ctx.lineTo(W * 0.52, cy + sign * H * 0.12);
  ctx.closePath();

  // metal gradient (top-left lit)
  const wg = ctx.createLinearGradient(W * 0.6, cy + sign * H * 0.02, W * 0.18, yEdge);
  if (sign < 0) {
    wg.addColorStop(0, P.playerHull);
    wg.addColorStop(0.5, P.playerHullMid);
    wg.addColorStop(1, P.playerHullShade);
  } else {
    wg.addColorStop(0, P.playerHullMid);
    wg.addColorStop(0.55, P.playerHullShade);
    wg.addColorStop(1, P.playerHullShade);
  }
  ctx.fillStyle = wg;
  ctx.fill();

  // cyan accent edge along leading edge
  ctx.shadowColor = P.playerAccent;
  ctx.shadowBlur = 5;
  ctx.strokeStyle = P.playerAccent;
  ctx.lineWidth = 1;
  ctx.globalAlpha = 0.9;
  ctx.beginPath();
  ctx.moveTo(W * 0.60, cy + sign * H * 0.05);
  ctx.lineTo(W * 0.40, yEdge);
  ctx.lineTo(W * 0.165, yEdge * 0.5 + cy * 0.5 + sign * H * 0.32);
  ctx.stroke();
  ctx.shadowBlur = 0;
  ctx.globalAlpha = 1;

  // panel line on wing
  ctx.strokeStyle = 'rgba(0,0,0,0.35)';
  ctx.lineWidth = 0.8;
  ctx.beginPath();
  ctx.moveTo(W * 0.50, cy + sign * H * 0.11);
  ctx.lineTo(W * 0.30, cy + sign * H * 0.30);
  ctx.stroke();
  ctx.restore();
}
drawWing(-1);
drawWing(1);

// =====================================================================
// TWIN REAR ENGINE NACELLES (left, behind fuselage root)
// =====================================================================
function drawNacelle(sign) {
  const ny = cy + sign * H * 0.20;
  ctx.save();
  // nacelle body
  ctx.beginPath();
  ctx.moveTo(W * 0.30, ny - H * 0.10);
  ctx.lineTo(W * 0.42, ny - H * 0.07);
  ctx.lineTo(W * 0.42, ny + H * 0.07);
  ctx.lineTo(W * 0.30, ny + H * 0.10);
  ctx.lineTo(tailX, ny + H * 0.075);
  ctx.lineTo(tailX, ny - H * 0.075);
  ctx.closePath();
  const ng = ctx.createLinearGradient(W * 0.42, ny - H * 0.1, tailX, ny + H * 0.1);
  ng.addColorStop(0, P.playerHullMid);
  ng.addColorStop(0.5, P.playerHullShade);
  ng.addColorStop(1, P.playerHullShade);
  ctx.fillStyle = ng;
  ctx.fill();

  // rim light
  ctx.strokeStyle = 'rgba(255,255,255,0.35)';
  ctx.lineWidth = 0.8;
  ctx.beginPath();
  ctx.moveTo(W * 0.30, ny - H * 0.10);
  ctx.lineTo(tailX, ny - H * 0.075);
  ctx.stroke();

  // glowing cyan engine intake at rear (left edge)
  ctx.shadowColor = P.playerAccent;
  ctx.shadowBlur = 9;
  const eg = ctx.createRadialGradient(tailX + 1, ny, 0, tailX + 1, ny, H * 0.10);
  eg.addColorStop(0, P.starWhite);
  eg.addColorStop(0.4, P.playerAccent);
  eg.addColorStop(1, 'rgba(34,227,255,0)');
  ctx.fillStyle = eg;
  ctx.beginPath();
  ctx.ellipse(tailX + 1, ny, H * 0.055, H * 0.075, 0, 0, Math.PI * 2);
  ctx.fill();
  ctx.shadowBlur = 0;
  ctx.restore();
}
drawNacelle(-1);
drawNacelle(1);

