ctx.lineWidth = 0.7;
ctx.beginPath();
ctx.moveTo(W * 0.30, cy - H * 0.12);
ctx.lineTo(W * 0.58, cy - H * 0.05);
ctx.moveTo(W * 0.30, cy + H * 0.12);
ctx.lineTo(W * 0.58, cy + H * 0.05);
ctx.moveTo(W * 0.45, cy - H * 0.16);
