// small accent stripe (player accent color) along upper fuselage
ctx.save();
ctx.strokeStyle = P.playerAccent;
ctx.globalAlpha = 0.7;
ctx.lineWidth = 1.2;
ctx.beginPath();
ctx.moveTo(W * 0.58, cy - H * 0.10);
ctx.lineTo(W * 0.72, cy - H * 0.05);
ctx.stroke();
ctx.restore();

// =====================================================================
// COCKPIT CANOPY — glowing cyan, near the front
// =====================================================================
ctx.save();
const ccx = W * 0.62;
const ccy = cy - H * 0.02;
ctx.shadowColor = P.playerCockpit;
ctx.shadowBlur = 8;
const cg = ctx.createRadialGradient(ccx + 2, ccy - 2, 0.5, ccx, ccy, H * 0.16);
cg.addColorStop(0, P.starWhite);
cg.addColorStop(0.35, P.playerCockpit);
cg.addColorStop(0.8, 'rgba(34,227,255,0.65)');
cg.addColorStop(1, 'rgba(34,227,255,0)');
ctx.fillStyle = cg;
ctx.beginPath();
// elongated canopy pointing toward nose
ctx.moveTo(ccx + W * 0.11, ccy);
ctx.quadraticCurveTo(ccx + W * 0.02, ccy - H * 0.12, ccx - W * 0.06, ccy - H * 0.045);
ctx.quadraticCurveTo(ccx - W * 0.085, ccy, ccx - W * 0.06, ccy + H * 0.045);
ctx.quadraticCurveTo(ccx + W * 0.02, ccy + H * 0.12, ccx + W * 0.11, ccy);
ctx.closePath();
ctx.fill();
ctx.shadowBlur = 0;

// canopy bright glint
ctx.fillStyle = 'rgba(255,255,255,0.85)';
ctx.beginPath();
ctx.ellipse(ccx + 1, ccy - H * 0.04, W * 0.018, H * 0.05, -0.5, 0, Math.PI * 2);
ctx.fill();

// canopy frame edge
ctx.strokeStyle = P.playerAccent;
ctx.lineWidth = 0.8;
ctx.globalAlpha = 0.8;
ctx.beginPath();
ctx.moveTo(ccx + W * 0.11, ccy);
ctx.quadraticCurveTo(ccx + W * 0.02, ccy - H * 0.12, ccx - W * 0.06, ccy - H * 0.045);
ctx.stroke();
ctx.restore();

ctx.restore();

// 3-frame engine flame strip, each 32x24, flame tapers LEFT, hot base at right edge
ctx.clearRect(0, 0, W, H);
ctx.lineCap = 'round';
ctx.lineJoin = 'round';

const FW = 32, FH = 24;
const cy = FH / 2; // vertical center within a frame

// per-frame flicker parameters: length factor, base half-height, wobble
const frames = [
  { len: 1.00, baseH: 7.0, wob: 0.0,  midBulge: 0.85 },
  { len: 0.78, baseH: 6.0, wob: 0.7,  midBulge: 0.95 },
  { len: 1.12, baseH: 7.6, wob: -0.5, midBulge: 0.78 },
];

for (let i = 0; i < 3; i++) {
  const f = frames[i];
  const ox = i * FW;
  const baseX = ox + FW - 2;          // hot base near right edge
  const tipX = ox + 3 + (1 - f.len) * 14; // tip toward left, varies with length
  const centerY = cy + f.wob;
  const span = baseX - tipX;

  // helper to build a teardrop plume path from base(right) to tip(left)
  const plume = (halfH, bulge) => {
    const midX = tipX + span * 0.42;
    const midH = halfH * bulge;
    ctx.beginPath();
    ctx.moveTo(baseX, centerY - halfH);
    // top edge: base -> bulge -> tip (slightly flickery curve)
    ctx.quadraticCurveTo(midX, centerY - midH, tipX, centerY - halfH * 0.18);
    ctx.quadraticCurveTo(tipX - 2, centerY, tipX, centerY + halfH * 0.18);
    // bottom edge: tip -> bulge -> base
    ctx.quadraticCurveTo(midX, centerY + midH, baseX, centerY + halfH);
    // round off the hot base
    ctx.quadraticCurveTo(baseX + 2, centerY, baseX, centerY - halfH);
    ctx.closePath();
  };

  // additive blending for a hot glow look
  ctx.save();
  ctx.globalCompositeOperation = 'lighter';

  // Layer 1: outer blue halo (transparent tip)
  let g1 = ctx.createLinearGradient(tipX, centerY, baseX, centerY);
  g1.addColorStop(0.0, 'rgba(0,0,0,0)');
  g1.addColorStop(0.35, P.playerFlameMid);
  g1.addColorStop(1.0, P.playerAccent);
  ctx.fillStyle = g1;
  ctx.shadowColor = P.playerFlameMid;
  ctx.shadowBlur = 6;
  ctx.globalAlpha = 0.55;
  plume(f.baseH, f.midBulge);
  ctx.fill();

  // Layer 2: cyan mid body
  let g2 = ctx.createLinearGradient(tipX, centerY, baseX, centerY);
  g2.addColorStop(0.0, 'rgba(0,0,0,0)');
  g2.addColorStop(0.30, 'rgba(34,227,255,0.0)');
  g2.addColorStop(0.55, P.playerAccent);
  g2.addColorStop(1.0, P.playerFlameCore);
  ctx.fillStyle = g2;
  ctx.shadowColor = P.playerAccent;
  ctx.shadowBlur = 5;
  ctx.globalAlpha = 0.85;
  plume(f.baseH * 0.66, f.midBulge * 0.95);
  ctx.fill();

  // Layer 3: white-hot core
  let g3 = ctx.createLinearGradient(tipX, centerY, baseX, centerY);
  g3.addColorStop(0.0, 'rgba(255,255,255,0)');
  g3.addColorStop(0.45, P.playerAccent);
  g3.addColorStop(0.8, P.playerFlameCore);
  g3.addColorStop(1.0, P.playerFlameCore);
  ctx.fillStyle = g3;
  ctx.shadowColor = P.playerFlameCore;
  ctx.shadowBlur = 4;
  ctx.globalAlpha = 0.95;
  plume(f.baseH * 0.34, f.midBulge);
  ctx.fill();

  // Hot base bloom - small bright radial at right edge
  let rb = ctx.createRadialGradient(baseX - 1, centerY, 0, baseX - 1, centerY, f.baseH * 0.9);
  rb.addColorStop(0.0, P.playerFlameCore);
  rb.addColorStop(0.4, P.playerAccent);
  rb.addColorStop(1.0, 'rgba(34,227,255,0)');
  ctx.fillStyle = rb;
  ctx.shadowBlur = 0;
  ctx.globalAlpha = 0.9;
  ctx.beginPath();
  ctx.arc(baseX - 1, centerY, f.baseH * 0.9, 0, Math.PI * 2);
  ctx.fill();

  // a couple of flickery spark streaks for texture
  ctx.globalAlpha = 0.5;
  ctx.strokeStyle = P.playerFlameCore;
  ctx.lineWidth = 0.8;
  ctx.shadowColor = P.playerAccent;
  ctx.shadowBlur = 3;
  for (let s = 0; s < 2; s++) {
    const yy = centerY + (s === 0 ? -1.6 : 1.8) + f.wob * 0.5;
    const sx = baseX - 3;
    const ex = tipX + span * (0.25 + Math.random() * 0.2);
    ctx.beginPath();
    ctx.moveTo(sx, yy);
    ctx.quadraticCurveTo((sx + ex) / 2, yy + (Math.random() - 0.5) * 2, ex, centerY + (Math.random() - 0.5));
    ctx.stroke();
  }

  ctx.restore();
}
ctx.shadowBlur = 0;
ctx.globalAlpha = 1;

var cx = W * 0.5, cy = H * 0.5;
var tipX = W - 2;      // pointed front (right)
var tailX = 3;         // short tail (left)

// ---- soft additive glow halo ----
ctx.save();
ctx.globalCompositeOperation = 'lighter';

// large outer cyan halo
var halo = ctx.createRadialGradient(cx + 2, cy, 0, cx + 2, cy, W * 0.55);
halo.addColorStop(0, 'rgba(34,227,255,0.55)');
halo.addColorStop(0.4, 'rgba(34,227,255,0.28)');
halo.addColorStop(1, 'rgba(34,227,255,0)');
ctx.fillStyle = halo;
ctx.beginPath();
ctx.ellipse(cx + 1, cy, W * 0.52, H * 0.55, 0, 0, Math.PI * 2);
ctx.fill();

// ---- main bolt body (elongated lozenge with pointed front + tail) ----
ctx.shadowColor = P.playerBulletGlow;
ctx.shadowBlur = 6;
var bodyGrad = ctx.createLinearGradient(tailX, 0, tipX, 0);
bodyGrad.addColorStop(0, 'rgba(34,227,255,0)');
bodyGrad.addColorStop(0.18, P.playerBulletGlow);
bodyGrad.addColorStop(0.55, P.playerBulletCore);
bodyGrad.addColorStop(0.85, P.playerBulletGlow);
bodyGrad.addColorStop(1, P.playerBulletGlow);
ctx.fillStyle = bodyGrad;
ctx.beginPath();
ctx.moveTo(tailX, cy);                                  // tail point (left)
ctx.quadraticCurveTo(cx * 0.55, cy - H * 0.42, cx + 2, cy - H * 0.40); // top edge
ctx.quadraticCurveTo(cx + 6, cy - H * 0.30, tipX, cy);  // pointed front (right)
ctx.quadraticCurveTo(cx + 6, cy + H * 0.30, cx + 2, cy + H * 0.40); // bottom edge
ctx.quadraticCurveTo(cx * 0.55, cy + H * 0.42, tailX, cy);
ctx.closePath();
ctx.fill();

// ---- bright white inner core along centerline ----
ctx.shadowColor = P.playerBulletCore;
ctx.shadowBlur = 4;
var coreGrad = ctx.createLinearGradient(cx - W * 0.32, 0, tipX, 0);
coreGrad.addColorStop(0, 'rgba(34,227,255,0)');
coreGrad.addColorStop(0.35, P.playerBulletCore);
coreGrad.addColorStop(0.75, P.playerBulletCore);
coreGrad.addColorStop(1, 'rgba(255,255,255,0)');
ctx.fillStyle = coreGrad;
ctx.beginPath();
ctx.moveTo(cx - W * 0.30, cy);
ctx.quadraticCurveTo(cx, cy - H * 0.20, tipX - 1.5, cy);
ctx.quadraticCurveTo(cx, cy + H * 0.20, cx - W * 0.30, cy);
ctx.closePath();
ctx.fill();

// ---- hottest pinpoint near the front ----
ctx.shadowBlur = 0;
var hot = ctx.createRadialGradient(cx + W * 0.18, cy, 0, cx + W * 0.18, cy, H * 0.5);
hot.addColorStop(0, P.playerBulletCore);
hot.addColorStop(1, 'rgba(255,255,255,0)');
ctx.fillStyle = hot;
ctx.beginPath();
ctx.ellipse(cx + W * 0.18, cy, H * 0.5, H * 0.32, 0, 0, Math.PI * 2);
ctx.fill();

ctx.restore();
ctx.shadowBlur = 0;

var cx = W / 2;
var cy = H / 2;

// Outer soft glow halo using additive blending
ctx.save();
ctx.globalCompositeOperation = 'lighter';

// Big soft horizontal glow
var halo = ctx.createRadialGradient(cx, cy, 0, cx, cy, W * 0.5);
halo.addColorStop(0, 'rgba(34,227,255,0.55)');
halo.addColorStop(0.4, 'rgba(34,227,255,0.22)');
halo.addColorStop(1, 'rgba(34,227,255,0)');
ctx.fillStyle = halo;
ctx.save();
ctx.translate(cx, cy);
ctx.scale(1.0, 0.62);
ctx.beginPath();
ctx.arc(0, 0, W * 0.5, 0, Math.PI * 2);
ctx.fill();
ctx.restore();

// Vertical falloff for the beam body (brightest along centerline)
var bodyTop = cy - 9;
var bodyH = 18;
var vgrad = ctx.createLinearGradient(0, bodyTop, 0, bodyTop + bodyH);
vgrad.addColorStop(0.0, 'rgba(34,227,255,0)');
vgrad.addColorStop(0.22, 'rgba(34,227,255,0.30)');
vgrad.addColorStop(0.5, 'rgba(170,245,255,0.95)');
vgrad.addColorStop(0.78, 'rgba(34,227,255,0.30)');
vgrad.addColorStop(1.0, 'rgba(34,227,255,0)');

// Horizontal falloff so ends fade slightly (it gets scaled, keep mostly solid)
var hMask = ctx.createLinearGradient(3, 0, W - 3, 0);
hMask.addColorStop(0.0, 'rgba(255,255,255,0)');
hMask.addColorStop(0.08, 'rgba(255,255,255,0.85)');
hMask.addColorStop(0.5, 'rgba(255,255,255,1)');
hMask.addColorStop(0.92, 'rgba(255,255,255,0.85)');
hMask.addColorStop(1.0, 'rgba(255,255,255,0)');

// Edge color band (cyan edges around the white core)
ctx.fillStyle = P.playerLaserEdge;
ctx.globalAlpha = 1;
ctx.shadowColor = P.playerLaserEdge;
ctx.shadowBlur = 10;
ctx.beginPath();
ctx.moveTo(2, cy);
ctx.lineTo(W * 0.10, cy - 8);
ctx.lineTo(W * 0.90, cy - 8);
ctx.lineTo(W - 2, cy);
ctx.lineTo(W * 0.90, cy + 8);
ctx.lineTo(W * 0.10, cy + 8);
ctx.closePath();
ctx.fill();
ctx.shadowBlur = 0;

// Apply vertical gradient body on top to brighten centerline
ctx.fillStyle = vgrad;
ctx.fillRect(0, bodyTop, W, bodyH);

ctx.restore();

// Bright white-cyan core line with energy ripple
ctx.save();
ctx.globalCompositeOperation = 'lighter';

// Core: a smooth horizontal band with a sine ripple in brightness
var steps = 80;
var coreHalf = 3.2;
ctx.beginPath();
for (var i = 0; i <= steps; i++) {
  var t = i / steps;
  var x = 3 + t * (W - 6);
  var edgeFade = Math.sin(Math.min(1, t / 0.1) * Math.PI / 2) * Math.sin(Math.min(1, (1 - t) / 0.1) * Math.PI / 2);
  var wob = Math.sin(t * Math.PI * 7) * 0.6;
  var y = cy - (coreHalf * edgeFade) - wob;
  if (i === 0) ctx.moveTo(x, y); else ctx.lineTo(x, y);
}
for (var j = steps; j >= 0; j--) {
  var t2 = j / steps;
  var x2 = 3 + t2 * (W - 6);
  var edgeFade2 = Math.sin(Math.min(1, t2 / 0.1) * Math.PI / 2) * Math.sin(Math.min(1, (1 - t2) / 0.1) * Math.PI / 2);
  var wob2 = Math.sin(t2 * Math.PI * 7) * 0.6;
  var y2 = cy + (coreHalf * edgeFade2) + wob2;
  ctx.lineTo(x2, y2);
}
ctx.closePath();
ctx.fillStyle = P.playerLaserCore;
ctx.shadowColor = P.playerLaserCore;
ctx.shadowBlur = 8;
ctx.fill();
ctx.shadowBlur = 0;

// Ultra-bright pinpoint centerline highlight
ctx.strokeStyle = P.playerLaserCore;
ctx.lineWidth = 1.1;
ctx.lineCap = 'round';
ctx.globalAlpha = 0.95;
ctx.beginPath();
for (var k = 0; k <= steps; k++) {
  var tk = k / steps;
  var xk = 4 + tk * (W - 8);
  var fade = Math.sin(Math.min(1, tk / 0.08) * Math.PI / 2) * Math.sin(Math.min(1, (1 - tk) / 0.08) * Math.PI / 2);
  var yk = cy + Math.sin(tk * Math.PI * 9) * 0.4 * fade;
  if (k === 0) ctx.moveTo(xk, yk); else ctx.lineTo(xk, yk);
}
ctx.stroke();
