// helper: rivet
function rivet(x, y, r) {
  const g = ctx.createRadialGradient(x - r*0.4, y - r*0.4, 0, x, y, r);
  g.addColorStop(0, P.enemyB_steel);
  g.addColorStop(0.5, P.enemyB_mid);
  g.addColorStop(1, P.enemyB_hull);
  ctx.fillStyle = g;
  ctx.beginPath();
  ctx.arc(x, y, r, 0, Math.PI * 2);
  ctx.fill();
}

// helper: glowing magenta vent
function vent(x, y, w, h, ang) {
  ctx.save();
  ctx.translate(x, y);
  ctx.rotate(ang || 0);
  ctx.shadowColor = P.enemyA_accent;
  ctx.shadowBlur = 12;
  const g = ctx.createLinearGradient(0, -h/2, 0, h/2);
  g.addColorStop(0, P.enemyA_accent);
  g.addColorStop(0.5, P.enemyA_core || P.enemyA_accent);
  g.addColorStop(1, P.enemyA_accent);
  ctx.fillStyle = g;
  ctx.beginPath();
  ctx.moveTo(-w/2, -h/2);
  ctx.lineTo(w/2, -h/2);
  ctx.lineTo(w/2, h/2);
  ctx.lineTo(-w/2, h/2);
  ctx.closePath();
  ctx.fill();
  ctx.restore();
}

