function cannonArm(topY) {
  ctx.save();
  // arm base anchored to hull, barrel reaching left
  const baseX = cx - 70;
  const tipX = 18;
  const armH = 30;
  // main barrel housing
  const g = ctx.createLinearGradient(0, topY - armH, 0, topY + armH);
  g.addColorStop(0, P.enemyB_steel);
  g.addColorStop(0.45, P.enemyB_mid);
  g.addColorStop(1, P.enemyB_hull);
  ctx.fillStyle = g;
  ctx.strokeStyle = P.enemyB_hull;
  ctx.lineWidth = 2;
  ctx.beginPath();
  ctx.moveTo(baseX, topY - armH);
  ctx.lineTo(tipX + 30, topY - armH * 0.7);
  ctx.lineTo(tipX, topY - armH * 0.55);
  ctx.lineTo(tipX, topY + armH * 0.55);
  ctx.lineTo(tipX + 30, topY + armH * 0.7);
  ctx.lineTo(baseX, topY + armH);
  ctx.closePath();
  ctx.fill();
  ctx.stroke();

  // top-left rim light on barrel
  ctx.strokeStyle = P.enemyB_accent;
  ctx.lineWidth = 1.6;
  ctx.globalAlpha = 0.85;
  ctx.beginPath();
  ctx.moveTo(baseX, topY - armH + 2);
  ctx.lineTo(tipX + 28, topY - armH * 0.7 + 2);
  ctx.stroke();
  ctx.globalAlpha = 1;

  // muzzle ring + dark bore
  ctx.fillStyle = P.enemyB_hull;
  ctx.beginPath();
  ctx.ellipse(tipX + 3, topY, 7, armH * 0.5, 0, 0, Math.PI * 2);
  ctx.fill();
  ctx.fillStyle = 'rgba(0,0,0,0.85)';
  ctx.beginPath();
  ctx.ellipse(tipX + 3, topY, 3.5, armH * 0.32, 0, 0, Math.PI * 2);
  ctx.fill();
  // faint amber ember at muzzle
  ctx.shadowColor = P.enemyB_warning;
  ctx.shadowBlur = 8;
  ctx.fillStyle = P.enemyB_warning;
  ctx.globalAlpha = 0.55;
  ctx.beginPath();
  ctx.arc(tipX + 3, topY, 2, 0, Math.PI * 2);
  ctx.fill();
  ctx.globalAlpha = 1;
  ctx.shadowBlur = 0;

  // barrel panel segments + rivets
  ctx.strokeStyle = 'rgba(0,0,0,0.4)';
  ctx.lineWidth = 1.4;
  for (let i = 1; i <= 3; i++) {
    const px = baseX + (tipX + 30 - baseX) * (i / 4);
    const hh = armH * (0.85 - i * 0.08);
    ctx.beginPath();
    ctx.moveTo(px, topY - hh);
    ctx.lineTo(px, topY + hh);
    ctx.stroke();
    rivet(px, topY - hh * 0.6, 1.6);
    rivet(px, topY + hh * 0.6, 1.6);
  }
  // accent vent slit on arm
  vent(baseX + 18, topY, 5, armH * 1.0, 0);
  ctx.restore();
}
