  ctx.lineTo(cx + halfW - r, cy - halfH);
  ctx.quadraticCurveTo(cx + halfW, cy - halfH, cx + halfW, cy - halfH + r);
  ctx.lineTo(cx + halfW, cy + halfH - r);
  ctx.quadraticCurveTo(cx + halfW, cy + halfH, cx + halfW - r, cy + halfH);
  ctx.lineTo(cx - halfW + r, cy + halfH);
  ctx.quadraticCurveTo(cx - halfW, cy + halfH, cx - halfW, cy + halfH - r);
  ctx.closePath();
}

