// FAR parallax starfield — fills canvas, low brightness, tiles horizontally.
const EDGE = 8; // wrap-safety margin

// --- Vertical gradient backdrop (tiles trivially) ---
const grad = ctx.createLinearGradient(0, 0, 0, H);
grad.addColorStop(0.0, P.voidTop);
grad.addColorStop(0.55, P.voidMid);
grad.addColorStop(1.0, P.horizonGlow);
ctx.fillStyle = grad;
ctx.fillRect(0, 0, W, H);

// Deterministic-ish pseudo random helper (committed once)
const rnd = () => Math.random();

// --- Very faint wispy nebula hints (low alpha, soft radial blobs) ---
ctx.save();
ctx.globalCompositeOperation = 'lighter';
const nebPlaces = [
  { x: W * 0.20, y: H * 0.62, r: 320, c: P.nebulaIndigo, a: 0.07 },
  { x: W * 0.70, y: H * 0.40, r: 360, c: P.nebulaMagenta, a: 0.05 },
  { x: W * 0.46, y: H * 0.80, r: 300, c: P.horizonGlow, a: 0.06 },
  { x: W * 0.88, y: H * 0.70, r: 280, c: P.nebulaIndigo, a: 0.045 }
];
for (const n of nebPlaces) {
  // draw the blob, plus wrapped copies so horizontal seam is clean
  for (const dx of [-W, 0, W]) {
    const cx = n.x + dx;
    if (cx + n.r < 0 || cx - n.r > W) continue;
    const g = ctx.createRadialGradient(cx, n.y, 0, cx, n.y, n.r);
    g.addColorStop(0, 'rgba(255,255,255,' + n.a + ')');
    g.addColorStop(0.35, n.c);
    g.addColorStop(1, 'rgba(0,0,0,0)');
    ctx.globalAlpha = n.a;
    ctx.fillStyle = g;
    ctx.beginPath();
    ctx.ellipse(cx, n.y, n.r, n.r * 0.6, (n.x % 7) * 0.1, 0, Math.PI * 2);
    ctx.fill();
  }
}
ctx.restore();

// Helper: place a star, and if near a horizontal edge also draw wrapped copies.
const placeStar = (drawFn, x) => {
  drawFn(x);
  if (x < EDGE) drawFn(x + W);
  if (x > W - EDGE) drawFn(x - W);
};

// --- Tiny faint scattered stars ---
const starCount = 320;
for (let i = 0; i < starCount; i++) {
  const x = rnd() * W;
  const y = rnd() * H;
  const dim = rnd() < 0.6;
  const col = dim ? P.starDim : P.starWhite;
  const sz = dim ? (0.4 + rnd() * 0.7) : (0.6 + rnd() * 1.0);
  const a = dim ? (0.10 + rnd() * 0.18) : (0.18 + rnd() * 0.22);

  const draw = (px) => {
    ctx.globalAlpha = a;
    ctx.fillStyle = col;
    ctx.beginPath();
    ctx.arc(px, y, sz, 0, Math.PI * 2);
    ctx.fill();
  };
  placeStar(draw, x);
}
ctx.globalAlpha = 1;

// --- A few soft twinkle glows (slightly brighter pinpoints with bloom) ---
const twinkleCount = 18;
ctx.save();
ctx.globalCompositeOperation = 'lighter';
for (let i = 0; i < twinkleCount; i++) {
  const x = rnd() * W;
  const y = rnd() * H * 0.92;
  const r = 1.0 + rnd() * 1.4;
  const glow = 4 + rnd() * 6;
  const a = 0.22 + rnd() * 0.14;

  const draw = (px) => {
    // soft halo
    const g = ctx.createRadialGradient(px, y, 0, px, y, glow);
    g.addColorStop(0, 'rgba(255,255,255,' + a + ')');
    g.addColorStop(1, 'rgba(255,255,255,0)');
    ctx.globalAlpha = 1;
    ctx.fillStyle = g;
    ctx.beginPath();
    ctx.arc(px, y, glow, 0, Math.PI * 2);
    ctx.fill();

    // bright core with neon bloom
    ctx.shadowColor = P.starWhite;
    ctx.shadowBlur = glow * 1.5;
    ctx.globalAlpha = Math.min(0.4, a + 0.12);
    ctx.fillStyle = P.starWhite;
    ctx.beginPath();
    ctx.arc(px, y, r, 0, Math.PI * 2);
    ctx.fill();

    // faint cross sparkle for the brightest few
    if (i % 3 === 0) {
      ctx.shadowBlur = 0;
      ctx.globalAlpha = a * 0.6;
      ctx.strokeStyle = P.starWhite;
      ctx.lineWidth = 0.5;
      ctx.beginPath();
      ctx.moveTo(px - glow, y);
      ctx.lineTo(px + glow, y);
      ctx.moveTo(px, y - glow);
      ctx.lineTo(px, y + glow);
      ctx.stroke();
    }
    ctx.shadowBlur = 0;
  };
  placeStar(draw, x);
}
ctx.restore();
ctx.globalAlpha = 1;
ctx.shadowBlur = 0;

// ============ MID PARALLAX LAYER — mostly transparent ============
// Transparent base: do NOT fill canvas. Keep all elements >=60px from seams.
ctx.save();
ctx.globalCompositeOperation = 'source-over';

const TAU = Math.PI * 2;
const seamPad = 70; // safety > 60

// tiny deterministic-ish rng (fine to vary; committed once)
function rnd(){ return Math.random(); }

// ---------- helper: soft faint nebula wisp (very low alpha) ----------
function nebulaWisp(cx, cy, rx, ry, col, a){
  ctx.save();
  ctx.globalCompositeOperation = 'lighter';
  const g = ctx.createRadialGradient(cx, cy, 0, cx, cy, Math.max(rx, ry));
  g.addColorStop(0, col);
  g.addColorStop(0.5, col);
  g.addColorStop(1, 'rgba(0,0,0,0)');
  ctx.globalAlpha = a;
  ctx.translate(cx, cy);
  ctx.scale(rx/Math.max(rx,ry), ry/Math.max(rx,ry));
  ctx.beginPath();
  ctx.arc(0, 0, Math.max(rx, ry), 0, TAU);
  ctx.fillStyle = g;
  ctx.fill();
  ctx.restore();
}

