// ---------- distant planet #1 (small, cool/indigo, terminator shaded) ----------
function distantPlanet(cx, cy, r, baseLo, baseHi, rimCol, rimA){
  ctx.save();
  // body sphere with upper-left light
  const g = ctx.createRadialGradient(cx - r*0.42, cy - r*0.42, r*0.1, cx, cy, r);
  g.addColorStop(0, baseHi);
  g.addColorStop(0.45, baseLo);
  g.addColorStop(1, 'rgba(2,4,12,1)');
  ctx.beginPath();
  ctx.arc(cx, cy, r, 0, TAU);
  ctx.fillStyle = g;
  ctx.fill();

  // subtle banding
  ctx.save();
  ctx.beginPath();
  ctx.arc(cx, cy, r, 0, TAU);
  ctx.clip();
  ctx.globalAlpha = 0.10;
  for(let i=0;i<4;i++){
    const yy = cy - r*0.5 + (i+rnd()*0.5)*(r*0.32);
    ctx.beginPath();
    ctx.ellipse(cx, yy, r*1.1, r*0.10, 0, 0, TAU);
    ctx.fillStyle = i%2? baseHi : 'rgba(0,0,0,1)';
    ctx.fill();
  }
  ctx.restore();

  // dark terminator (shadow side lower-right)
  ctx.save();
  ctx.beginPath();
  ctx.arc(cx, cy, r, 0, TAU);
  ctx.clip();
  const sg = ctx.createRadialGradient(cx + r*0.55, cy + r*0.55, r*0.1, cx + r*0.4, cy + r*0.4, r*1.5);
  sg.addColorStop(0, 'rgba(0,0,0,0.0)');
  sg.addColorStop(1, 'rgba(0,0,0,0.78)');
  ctx.fillStyle = sg;
  ctx.fillRect(cx - r, cy - r, r*2, r*2);
  ctx.restore();

  // thin rim light arc on lit edge
  ctx.save();
  ctx.globalCompositeOperation = 'lighter';
  ctx.lineWidth = Math.max(1, r*0.025);
  ctx.strokeStyle = rimCol;
  ctx.shadowColor = rimCol;
  ctx.shadowBlur = r*0.35;
  ctx.globalAlpha = rimA;
  ctx.beginPath();
  ctx.arc(cx, cy, r*0.985, Math.PI*1.05, Math.PI*1.95);
  ctx.stroke();
  ctx.restore();
  ctx.restore();
}

