// ---------- ringed gas giant (the hero element, but still low brightness) ----------
function ringedGiant(cx, cy, r){
  ctx.save();
  // back half of ring (behind planet)
  function drawRing(frontHalf){
    ctx.save();
    ctx.translate(cx, cy);
    ctx.rotate(-0.34);
    ctx.scale(1, 0.30);
    const ro = r*2.15, ri = r*1.30;
    ctx.beginPath();
    if(frontHalf){
      ctx.arc(0,0, ro, 0, Math.PI, false);
      ctx.arc(0,0, ri, Math.PI, 0, true);
    } else {
      ctx.arc(0,0, ro, Math.PI, TAU, false);
      ctx.arc(0,0, ri, TAU, Math.PI, true);
    }
    ctx.closePath();
    const rg = ctx.createLinearGradient(-ro, 0, ro, 0);
    rg.addColorStop(0.0, 'rgba(0,0,0,0)');
    rg.addColorStop(0.18, P.enemyB_steel);
    rg.addColorStop(0.5, P.enemyB_accent);
    rg.addColorStop(0.82, P.enemyB_steel);
    rg.addColorStop(1.0, 'rgba(0,0,0,0)');
    ctx.globalAlpha = frontHalf ? 0.55 : 0.40;
    ctx.fillStyle = rg;
    ctx.fill();
    // ring banding lines
    ctx.globalAlpha = frontHalf ? 0.30 : 0.20;
    ctx.lineWidth = r*0.02;
    ctx.strokeStyle = 'rgba(8,10,18,1)';
    for(let k=0;k<3;k++){
      const rr = ri + (ro-ri)*(0.25+k*0.28);
      ctx.beginPath();
      ctx.arc(0,0, rr, frontHalf?0:Math.PI, frontHalf?Math.PI:TAU);
      ctx.stroke();
    }
    ctx.restore();
  }

  drawRing(false); // back

  // planet body
  const g = ctx.createRadialGradient(cx - r*0.45, cy - r*0.45, r*0.12, cx, cy, r);
  g.addColorStop(0, P.enemyB_accent);
  g.addColorStop(0.4, P.enemyB_warning);
  g.addColorStop(0.75, P.enemyB_steel);
  g.addColorStop(1, 'rgba(4,4,10,1)');
  ctx.globalAlpha = 0.92;
  ctx.beginPath();
  ctx.arc(cx, cy, r, 0, TAU);
  ctx.fillStyle = g;
  ctx.fill();
  ctx.globalAlpha = 1;

  // atmospheric bands
  ctx.save();
  ctx.beginPath(); ctx.arc(cx, cy, r, 0, TAU); ctx.clip();
  ctx.globalAlpha = 0.14;
  for(let i=0;i<6;i++){
    const yy = cy - r*0.8 + (i+0.3)*(r*0.30);
    ctx.beginPath();
    ctx.ellipse(cx, yy, r*1.2, r*0.075, 0, 0, TAU);
    ctx.fillStyle = i%2? P.enemyB_warning : 'rgba(10,6,4,1)';
    ctx.fill();
  }
  // a faint storm spot
  ctx.globalAlpha = 0.22;
  ctx.beginPath();
  ctx.ellipse(cx + r*0.22, cy + r*0.18, r*0.16, r*0.10, 0, 0, TAU);
  ctx.fillStyle = P.enemyB_warning;
  ctx.fill();
  ctx.restore();

  // shadow side
  ctx.save();
  ctx.beginPath(); ctx.arc(cx, cy, r, 0, TAU); ctx.clip();
  const sg = ctx.createRadialGradient(cx + r*0.5, cy + r*0.5, r*0.1, cx + r*0.35, cy + r*0.35, r*1.6);
  sg.addColorStop(0, 'rgba(0,0,0,0)');
  sg.addColorStop(1, 'rgba(0,0,0,0.72)');
  ctx.fillStyle = sg;
  ctx.fillRect(cx - r, cy - r, r*2, r*2);
  ctx.restore();

  // lit rim
  ctx.save();
  ctx.globalCompositeOperation = 'lighter';
  ctx.lineWidth = r*0.02;
  ctx.strokeStyle = P.enemyB_accent;
  ctx.shadowColor = P.enemyB_accent;
  ctx.shadowBlur = r*0.4;
  ctx.globalAlpha = 0.4;
  ctx.beginPath();
  ctx.arc(cx, cy, r*0.99, Math.PI*1.02, Math.PI*1.98);
  ctx.stroke();
  ctx.restore();

  drawRing(true); // front

  ctx.restore();
}

