// ---------- asteroid cluster (silhouetted lumps with rim light) ----------
function asteroidCluster(cx, cy, count, baseR, rimCol, rimA){
  ctx.save();
  for(let i=0;i<count;i++){
    const ang = rnd()*TAU;
    const dist = rnd()*baseR*2.2;
    const ax = cx + Math.cos(ang)*dist;
    const ay = cy + Math.sin(ang)*dist*0.6;
    const r = baseR*(0.35 + rnd()*0.85);

    // lumpy silhouette
    ctx.beginPath();
    const pts = 7 + ((rnd()*3)|0);
    for(let p=0;p<=pts;p++){
      const a = (p/pts)*TAU;
      const rr = r*(0.78 + rnd()*0.4);
      const x = ax + Math.cos(a)*rr;
      const y = ay + Math.sin(a)*rr;
      if(p===0) ctx.moveTo(x,y); else ctx.lineTo(x,y);
    }
    ctx.closePath();
    const g = ctx.createRadialGradient(ax - r*0.4, ay - r*0.4, r*0.1, ax, ay, r*1.2);
    g.addColorStop(0, 'rgba(20,20,30,1)');
    g.addColorStop(1, 'rgba(5,5,10,1)');
    ctx.fillStyle = g;
    ctx.fill();

    // rim light on upper-left
    ctx.save();
    ctx.globalCompositeOperation = 'lighter';
    ctx.lineWidth = 1.2;
    ctx.strokeStyle = rimCol;
    ctx.shadowColor = rimCol;
    ctx.shadowBlur = 5;
    ctx.globalAlpha = rimA * (0.6 + rnd()*0.4);
    ctx.beginPath();
    ctx.arc(ax, ay, r*0.95, Math.PI*1.05, Math.PI*1.75);
    ctx.stroke();
    ctx.restore();
  }
  ctx.restore();
}

