// ---- NEAR FOREGROUND TILEABLE FRAME (top & bottom plating, transparent center) ----
// Transparent background by default (do NOT fill whole canvas).

// Helper: seamless seeded-ish noise via sin combos
function rng(seed){ let s = Math.sin(seed*127.1+311.7)*43758.5453; return s - Math.floor(s); }

// Draw a horizontal run of armor plates that tiles seamlessly across width W.
// 'bandTop' = top y of band, 'bandH' = band height, 'flip' inverts the inner edge direction.
function drawPlateBand(bandTop, bandH, flip){
  const innerY = flip ? bandTop : bandTop + bandH;          // edge facing play area
  const outerY = flip ? bandTop + bandH : bandTop;          // edge facing screen border
  const dir = flip ? 1 : -1;                                // direction toward play area

  // Base metal gradient (vertical, light from upper-left so top of band brighter)
  const g = ctx.createLinearGradient(0, outerY, 0, innerY);
  g.addColorStop(0, P.enemyB_steel);
  g.addColorStop(0.45, P.enemyB_mid);
  g.addColorStop(1, P.enemyB_hull);
  ctx.fillStyle = g;
  ctx.fillRect(0, bandTop, W, bandH);

  // Subtle large diagonal sheen
  ctx.save();
  ctx.globalCompositeOperation = 'lighter';
  const sheen = ctx.createLinearGradient(0, outerY, W*0.18, innerY);
  sheen.addColorStop(0, 'rgba(180,200,220,0.10)');
  sheen.addColorStop(0.5, 'rgba(120,140,170,0.02)');
  sheen.addColorStop(1, 'rgba(0,0,0,0)');
  ctx.fillStyle = sheen;
  ctx.fillRect(0, bandTop, W, bandH);
  ctx.restore();

  // --- Plate segmentation that tiles: choose plate count that divides W evenly ---
  const plates = 16;                 // even division => seamless
  const pw = W / plates;

  for(let i=0;i<=plates;i++){        // <=plates so the wrap seam plate at x=W mirrors x=0
    const x = i*pw;
    const r1 = rng(i*3.3 + (flip?7.7:1.1));
    const r2 = rng(i*5.1 + (flip?2.2:9.9));

    // Vertical panel groove between plates (dark recess + bright catch-light edge)
    ctx.save();
    ctx.strokeStyle = 'rgba(0,0,0,0.55)';
    ctx.lineWidth = 3;
    ctx.beginPath();
    ctx.moveTo(x, bandTop+1);
    ctx.lineTo(x, bandTop+bandH-1);
    ctx.stroke();
    // catch light on the upper-left side of the groove
    ctx.strokeStyle = 'rgba(190,210,230,0.18)';
    ctx.lineWidth = 1;
    ctx.beginPath();
    ctx.moveTo(x+1.5, bandTop+1);
    ctx.lineTo(x+1.5, bandTop+bandH-1);
    ctx.stroke();
    ctx.restore();

    if(i===plates) break; // edge groove only for the wrap seam

    // Per-plate inner shading to give bevel volume
    const px = x + 2;
    const pinW = pw - 4;
    const bevel = ctx.createLinearGradient(px, outerY, px, innerY);
    bevel.addColorStop(0, 'rgba(170,190,210,0.16)');
    bevel.addColorStop(0.5, 'rgba(0,0,0,0)');
    bevel.addColorStop(1, 'rgba(0,0,0,0.30)');
    ctx.fillStyle = bevel;
    ctx.fillRect(px, bandTop+1, pinW, bandH-2);

    // Rivets along the outer edge of each plate
    ctx.save();
    const rivetY = outerY + dir*7;
    for(let rcol=0; rcol<3; rcol++){
      const rx = px + 8 + rcol*(pinW-16)/2;
      ctx.beginPath();
      ctx.fillStyle = P.enemyB_steel;
      ctx.arc(rx, rivetY, 2.1, 0, Math.PI*2);
      ctx.fill();
      ctx.beginPath();
      ctx.fillStyle = 'rgba(20,24,30,0.8)';
      ctx.arc(rx+0.7, rivetY+0.7, 1.0, 0, Math.PI*2);
      ctx.fill();
      ctx.beginPath();
      ctx.fillStyle = 'rgba(210,225,240,0.5)';
      ctx.arc(rx-0.6, rivetY-0.6, 0.8, 0, Math.PI*2);
      ctx.fill();
    }
    ctx.restore();

    // A few darker vent slots on some plates
    if(r1 > 0.5){
      ctx.save();
      ctx.fillStyle = 'rgba(8,10,14,0.85)';
      const slots = 3;
      const slotW = pinW*0.5/slots;
      const slotStartX = px + pinW*0.25;
      const slotY = bandTop + bandH*0.42;
      for(let s=0;s<slots;s++){
        ctx.fillRect(slotStartX + s*slotW*1.4, slotY, slotW, bandH*0.16);
      }
      // thin amber rim on vents
      ctx.strokeStyle = 'rgba(255,150,40,0.18)';
      ctx.lineWidth = 1;
      ctx.strokeRect(slotStartX-1, slotY-1, slots*slotW*1.4, bandH*0.16+2);
      ctx.restore();
    }
  }

  // --- Jagged asteroid / hull silhouette edge facing the play area (tileable) ---
  // Build a periodic edge so left and right match. Use sum of sines with integer periods.
  ctx.save();
  ctx.beginPath();
  ctx.moveTo(0, innerY);
  const steps = 256;
  const amp = Math.min(18, bandH*0.30);
  for(let i=0;i<=steps;i++){
    const t = i/steps;
    const ang = t*Math.PI*2;
    // integer-frequency sines => seamless wrap
    const e = Math.sin(ang*5)*0.5 + Math.sin(ang*11+1.3)*0.28 + Math.sin(ang*23+0.7)*0.16;
    const jag = (Math.abs(Math.sin(ang*37+2.1))>0.86) ? 0.5 : 0; // occasional chips
    const ey = innerY + dir*(amp*(0.5 + 0.5*e) + amp*jag);
    ctx.lineTo(t*W, ey);
  }
  // close polygon back along the outer border
  ctx.lineTo(W, outerY);
  ctx.lineTo(0, outerY);
  ctx.closePath();
  // re-fill with band gradient so the jagged region reads as solid hull, not a void
  const eg = ctx.createLinearGradient(0, outerY, 0, innerY);
  eg.addColorStop(0, P.enemyB_steel);
  eg.addColorStop(0.5, P.enemyB_mid);
  eg.addColorStop(1, P.enemyB_hull);
  ctx.fillStyle = eg;
  ctx.fill();

  // Bright accent rim line tracing the jagged inner edge (silhouette readability)
  ctx.beginPath();
  for(let i=0;i<=steps;i++){
    const t = i/steps;
    const ang = t*Math.PI*2;
    const e = Math.sin(ang*5)*0.5 + Math.sin(ang*11+1.3)*0.28 + Math.sin(ang*23+0.7)*0.16;
    const jag = (Math.abs(Math.sin(ang*37+2.1))>0.86) ? 0.5 : 0;
    const ey = innerY + dir*(amp*(0.5 + 0.5*e) + amp*jag);
    if(i===0) ctx.moveTo(t*W, ey); else ctx.lineTo(t*W, ey);
  }
  ctx.strokeStyle = P.enemyB_accent;
  ctx.lineWidth = 1.6;
  ctx.shadowColor = P.enemyB_accent;
  ctx.shadowBlur = 8;
  ctx.globalAlpha = 0.85;
  ctx.stroke();
  ctx.shadowBlur = 0;
  ctx.globalAlpha = 1;
  ctx.restore();
}

// ---- Conduit pipes running horizontally, glowing; placed at integer-periodic x so they tile ----
function drawConduit(yCenter, thick, color, glowColor, phase){
  ctx.save();
  // pipe body
  const pg = ctx.createLinearGradient(0, yCenter-thick, 0, yCenter+thick);
  pg.addColorStop(0, P.enemyB_steel);
  pg.addColorStop(0.5, P.enemyB_mid);
  pg.addColorStop(1, P.enemyB_hull);
  ctx.fillStyle = pg;
  ctx.fillRect(0, yCenter-thick, W, thick*2);
  // top highlight
  ctx.strokeStyle = 'rgba(200,215,230,0.35)';
  ctx.lineWidth = 1;
  ctx.beginPath(); ctx.moveTo(0, yCenter-thick+1); ctx.lineTo(W, yCenter-thick+1); ctx.stroke();

  // glowing core line
  ctx.globalCompositeOperation = 'lighter';
  ctx.strokeStyle = color;
  ctx.lineWidth = Math.max(1.5, thick*0.5);
  ctx.shadowColor = glowColor;
  ctx.shadowBlur = 14;
  ctx.beginPath(); ctx.moveTo(0, yCenter); ctx.lineTo(W, yCenter); ctx.stroke();
  ctx.shadowBlur = 0;

  // glow nodes at evenly-spaced (tileable) intervals
  const nodes = 12; // divides W evenly => seamless
  const nx = W/nodes;
  for(let i=0;i<nodes;i++){
    const x = i*nx + (phase*nx);
    const xx = ((x % W) + W) % W;
    ctx.beginPath();
    ctx.fillStyle = color;
    ctx.shadowColor = glowColor;
    ctx.shadowBlur = 16;
    ctx.arc(xx, yCenter, thick*0.9, 0, Math.PI*2);
    ctx.fill();
    // wrap copy for nodes near the seam
    if(xx > W - thick*2){ ctx.beginPath(); ctx.arc(xx - W, yCenter, thick*0.9, 0, Math.PI*2); ctx.fill(); }
    if(xx < thick*2){ ctx.beginPath(); ctx.arc(xx + W, yCenter, thick*0.9, 0, Math.PI*2); ctx.fill(); }
  }
  ctx.shadowBlur = 0;
  ctx.restore();
}

