// Helper: draw a soft radial cloud, wrapping horizontally so it tiles seamlessly.
function cloud(cx, cy, rx, ry, color, peakAlpha) {
  for (let dx = -W; dx <= W; dx += W) {
    const x = cx + dx;
    // Skip copies entirely off-canvas (with margin for radius)
    if (x + rx < -8 || x - rx > W + 8) continue;
    ctx.save();
    ctx.translate(x, cy);
    ctx.scale(1, ry / rx);
    const g = ctx.createRadialGradient(0, 0, 0, 0, 0, rx);
    g.addColorStop(0.0, color);
    g.addColorStop(0.45, 'rgba(0,0,0,0)'); // placeholder, replaced below via alpha layering
    g.addColorStop(1.0, 'rgba(0,0,0,0)');
    // Build gradient with proper alpha falloff using the palette color.
    const g2 = ctx.createRadialGradient(0, 0, 0, 0, 0, rx);
    g2.addColorStop(0.0, color);
    g2.addColorStop(0.55, color);
    g2.addColorStop(1.0, 'rgba(0,0,0,0)');
    ctx.globalAlpha = peakAlpha;
    ctx.fillStyle = g2;
    ctx.beginPath();
    ctx.arc(0, 0, rx, 0, Math.PI * 2);
    ctx.fill();
    ctx.restore();
  }
}

